const health = $input.first().json || {};
const account = health.account || {};
const guard = health.guard || {};
const config = health.mt5_connection_config || {};
const guardBlockers = Array.isArray(guard.blockers) ? guard.blockers : [];
const accountBlockers = Array.isArray(guard.live_account_blockers) ? guard.live_account_blockers : [];
const tradeMode = account.trade_mode_label || 'unknown';
const demoModeOk = ['demo', 'contest'].includes(tradeMode);
const ready = Boolean(
  health.ok === true &&
  health.live_enabled === true &&
  account.connected === true &&
  demoModeOk &&
  guard.ok === true &&
  guardBlockers.length === 0 &&
  accountBlockers.length === 0
);

return [{
  json: {
    ok: ready,
    bridge_ready: ready,
    status: ready ? 'demo_live_ready' : 'blocked',
    live_enabled: health.live_enabled === true,
    mt5_connected: account.connected === true,
    trade_mode: tradeMode,
    demo_mode_ok: demoModeOk,
    guard_ok: guard.ok === true,
    real_allowed: config.allow_real_account === true,
    require_demo_account: config.require_demo_account !== false,
    blockers: [...guardBlockers, ...accountBlockers, ...(health.ok === true ? [] : ['MT5 bridge health endpoint did not return ok=true.'])],
    checked_at: new Date().toISOString()
  }
}];

const prices = $input.first().json.prices || [];
const period = 50;
if (prices.length < period + 1) {
  return [{ json: { ok: false, reason: 'Not enough hourly candles', signal: false } }];
}

const closes = prices.map((row) => Number(row[1])).filter((value) => Number.isFinite(value));
let ema = closes.slice(0, period).reduce((sum, value) => sum + value, 0) / period;
const multiplier = 2 / (period + 1);
for (let index = period; index < closes.length; index += 1) {
  ema = (closes[index] - ema) * multiplier + ema;
}

const currentPrice = closes.at(-1);
const previousPrice = closes.at(-2);
const atrProxy = Math.max(currentPrice * 0.01, Math.abs(currentPrice - previousPrice) * 2);
const signal = currentPrice > ema;
const stopLoss = Number((currentPrice - atrProxy).toFixed(2));
const takeProfit = Number((currentPrice + atrProxy * 2).toFixed(2));
const rr = Number(((takeProfit - currentPrice) / Math.max(currentPrice - stopLoss, 1)).toFixed(2));

return [{
  json: {
    ok: true,
    symbol: 'BTCUSD',
    direction: 'LONG',
    setup: 'BTCUSD hourly close above EMA50',
    current_price: Number(currentPrice.toFixed(2)),
    ema50: Number(ema.toFixed(2)),
    signal,
    entry: Number(currentPrice.toFixed(2)),
    stopLoss,
    takeProfit,
    rewardRisk: rr,
    riskPercent: 0.25,
    spreadPercent: 0.03,
    newsRisk: 'low',
    timestamp: new Date().toISOString(),
    note: signal ? 'Candidate only. Zeus risk gate and manual approval are still required.' : 'No candidate: BTCUSD is not above EMA50.'
  }
}];
